const overall = $('Get Overall Stats').first().json;
const byProvince = $('Stats by Province').all().map(i => i.json);
const byType = $('Stats by Property Type').all().map(i => i.json);
const bySource = $('Stats by Source').all().map(i => i.json);

const reportDate = new Date().toLocaleDateString('en-ZA', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toLocaleDateString('en-ZA');
const weekEnd = new Date().toLocaleDateString('en-ZA');

// Format currency
const fmt = (n) => 'R ' + Number(n).toLocaleString('en-ZA', { maximumFractionDigits: 0 });

const slackMessage = [
  `*PuraEstate Weekly Market Summary*`,
  `${weekStart} - ${weekEnd}`,
  ``,
  `*Overall Market*`,
  `• Total Active Listings: ${Number(overall.total_active).toLocaleString()}`,
  `• New This Week: ${Number(overall.new_this_week).toLocaleString()}`,
  `• New Today: ${Number(overall.new_today).toLocaleString()}`,
  `• Average Price: ${fmt(overall.avg_price)}`,
  `• Median Price: ${fmt(overall.median_price)}`,
  `• Price Range: ${fmt(overall.min_price)} - ${fmt(overall.max_price)}`,
  `• Provinces: ${overall.provinces_covered} | Cities: ${overall.cities_covered}`,
  ``,
  `*By Province (Top 5)*`,
  ...byProvince.slice(0, 5).map(p => 
    `• ${p.province}: ${p.listings} listings | Avg ${fmt(p.avg_price)} | +${p.new_this_week} this week`
  ),
  ``,
  `*By Property Type*`,
  ...byType.map(t => 
    `• ${t.property_type}: ${t.count} listings | Avg ${fmt(t.avg_price)}`
  )
].join('\n');

const emailHtml = `
<!DOCTYPE html>
<html>
<head><style>
body{font-family:Georgia,serif;color:#333;margin:0;background:#f9f9f9;}
.container{max-width:700px;margin:0 auto;background:white;}
.header{background:linear-gradient(135deg,#1a472a 0%,#2d6a4f 100%);color:white;padding:40px 30px;text-align:center;}
.header h1{margin:0;font-size:28px;letter-spacing:1px;}
.header .subtitle{opacity:0.85;margin:8px 0 0;font-size:14px;}
.section{padding:25px 30px;border-bottom:1px solid #eee;}
.section h2{color:#1a472a;font-size:18px;margin:0 0 15px;padding-bottom:8px;border-bottom:2px solid #e8f5e9;}
.stat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin:15px 0;}
.stat{background:#f0f7f4;border-radius:8px;padding:15px;text-align:center;}
.stat .number{font-size:22px;font-weight:bold;color:#1a472a;}
.stat .label{font-size:12px;color:#666;margin-top:4px;}
.province-row{display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f5f5f5;}
.province-name{font-weight:bold;color:#1a472a;}
.badge{background:#e8f5e9;color:#1a472a;padding:2px 8px;border-radius:10px;font-size:11px;}
footer{background:#1a472a;color:white;padding:20px;text-align:center;font-size:12px;}
</style></head>
<body>
<div class="container">
<div class="header">
  <h1>PuraEstate Market Summary</h1>
  <div class="subtitle">${weekStart} - ${weekEnd}</div>
</div>

<div class="section">
  <h2>Overall Market</h2>
  <div class="stat-grid">
    <div class="stat"><div class="number">${Number(overall.total_active).toLocaleString()}</div><div class="label">Active Listings</div></div>
    <div class="stat"><div class="number">${Number(overall.new_this_week).toLocaleString()}</div><div class="label">New This Week</div></div>
    <div class="stat"><div class="number">${fmt(overall.median_price)}</div><div class="label">Median Price</div></div>
    <div class="stat"><div class="number">${fmt(overall.avg_price)}</div><div class="label">Average Price</div></div>
    <div class="stat"><div class="number">${overall.provinces_covered}</div><div class="label">Provinces</div></div>
    <div class="stat"><div class="number">${overall.cities_covered}</div><div class="label">Cities</div></div>
  </div>
</div>

<div class="section">
  <h2>By Province</h2>
  ${byProvince.map(p => `
  <div class="province-row">
    <span class="province-name">${p.province}</span>
    <span>${p.listings} listings</span>
    <span>${fmt(p.avg_price)} avg</span>
    <span class="badge">+${p.new_this_week} new</span>
  </div>`).join('')}
</div>

<div class="section">
  <h2>By Property Type</h2>
  ${byType.map(t => `
  <div class="province-row">
    <span class="province-name" style="text-transform:capitalize">${t.property_type}</span>
    <span>${t.count} listings</span>
    <span>${fmt(t.avg_price)} avg</span>
    <span>${t.avg_bedrooms > 0 ? t.avg_bedrooms + ' avg beds' : ''}</span>
  </div>`).join('')}
</div>

<div class="section">
  <h2>Data Sources</h2>
  ${bySource.map(s => `
  <div class="province-row">
    <span class="province-name">${s.source}</span>
    <span>${s.listings} total</span>
    <span class="badge">+${s.added_this_week} this week</span>
  </div>`).join('')}
</div>

<footer>PuraEstate Intelligence Platform | ${reportDate}</footer>
</div>
</body></html>`;

return [{
  json: {
    report_date: reportDate,
    week_start: weekStart,
    week_end: weekEnd,
    overall,
    by_province: byProvince,
    by_type: byType,
    by_source: bySource,
    slack_message: slackMessage,
    email_html: emailHtml
  }
}];
